var out = $input.first().json.stdout || '';
var si = out.indexOf('\n=REPORT=\n');
var commitSection = (si > -1 ? out.slice(0, si) : out).replace('=COMMITS=\n', '');
var reportMd = si > -1 ? out.slice(si + 10).trim() : 'No report yet.';

var commits = [];
commitSection.trim().split('\n').forEach(function(l) {
  l = l.trim(); if (!l) return;
  var c = l.split('|');
  if (c.length >= 3) commits.push([c[0], c[1], c[2], c[3] || '']);
});

var rows = commits.map(function(c) {
  return '<tr><td class=h>' + c[0] + '</td><td class=w>' + c[1] + '</td><td>' + c[2] + '</td><td class=a>' + c[3] + '</td></tr>';
}).join('');

var table = commits.length
  ? '<table><thead><tr><th>Hash</th><th>When</th><th>Message</th><th>Author</th></tr></thead><tbody>' + rows + '</tbody></table>'
  : '<p class=m>No commits yet.</p>';

var rj = JSON.stringify(reportMd).replace(/<\//g, '<\/');

var html = [
  '<!doctype html><html><head><meta charset=utf-8><title>Qwen Dashboard</title>',
  '<' + 'script src=https://cdn.jsdelivr.net/npm/marked/marked.min.js></' + 'script>',
  '<style>',
  ':root{--bg:#0b0d12;--p:#12151c;--b:#222733;--t:#e6e9ef;--m:#8b93a7;--a:#7c6cf5}',
  '*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--t);font:15px/1.6 system-ui,sans-serif;padding:2rem 3rem;max-width:980px}',
  'h1{color:var(--a);margin:0 0 .3rem}p.sub{color:var(--m);margin:0 0 1.2rem}',
  'h2{border-bottom:1px solid var(--b);padding-bottom:.3rem;margin-top:2rem}',
  'table{border-collapse:collapse;width:100%;margin:1rem 0}',
  'th,td{border:1px solid var(--b);padding:.4rem .7rem;text-align:left;font-size:.87rem}',
  'th{background:#1b202b;color:var(--m)}.h{font-family:monospace;color:var(--a)}.w,.a{color:var(--m);white-space:nowrap}.m{color:var(--m)}',
  '.box{background:var(--p);border:1px solid var(--b);border-radius:8px;padding:1.5rem;margin-top:1rem}',
  '.box code{background:#1b202b;padding:.15em .4em;border-radius:4px;font-size:.85em}',
  '.box pre{background:#1b202b;padding:1rem;border-radius:6px;overflow:auto}',
  'button{background:var(--a);color:#fff;border:none;padding:.5rem 1.2rem;border-radius:6px;cursor:pointer;font-size:.9rem}',
  'button:hover{opacity:.85}#st{margin-left:1rem;font-size:.85rem;color:var(--m)}',
  '</style></head><body>',
  '<h1>Qwen Agent Dashboard</h1>',
  '<p class=sub>qwen-agent-collective \u2014 autonomous coding loop</p>',
  '<button onclick=run()>\u25b6 Run Coder Now</button><span id=st></span>',
  '<h2>Recent Commits</h2>',
  table,
  '<h2>Latest Report</h2><div class=box id=rpt></div>',
  '<' + 'script>',
  'var R=' + rj + ';',
  'document.getElementById("rpt").innerHTML=marked.parse(R);',
  'function run(){',
  '  var s=document.getElementById("st");',
  '  s.textContent="Running\u2026";',
  '  fetch("/webhook/qwen-coder",{method:"POST",headers:{"Content-Type":"application/json"},body:"{}"})',
  '  .then(function(r){return r.json()})',
  '  .then(function(d){s.textContent=JSON.stringify(d);setTimeout(function(){location.reload()},3000)})',
  '  .catch(function(e){s.textContent="Error: "+e});',
  '}',
  '</' + 'script></body></html>'
].join('');

return [{ json: { html: html } }];
